skinparam sequenceMessageAlign center
participant "VideoSink" as VideoSink #96D8FF
participant "VideoDecoderBridge" as VideoDecoderBridge #F5CBA7
participant "VCMGenericDecoder" as VCMGenericDecoder #AED6F1
