participant "SurfaceTextureHelper" as SurfaceTextureHelper #EBDEF0


group Receive RTP 
    participant "RTCPReceiver" as RTCPReceiver #FCF3CF
    group SignalReadEvent  
        activate DTLSSocket
            note right of  DTLSSocket : OnDataReceived()
                loop while(true) {
                    alt if(ssl_) {
                        ssl_->ReceivePacket();
                            else{
                                udp_socket->RecvFrom(packet);
                                    }   
                                        packet_transport_proxy_.OnSentPacket(sent_packet_size_);    
                                            transport.SendOutgoingPacket(&packet_copy);     
                                                rtcp_receiver.ProcessFeedbackPackets(pending_feedback_packets_, &rtt_ms);      
                                                    rtp_rtcp_module.OnSendReport(rtt_ms, send_time_us);       
                                                        signal_read_event.Signal();        
                                                            break;            
                                                                }}
                                                                    deactivate DTLSSocket

end 

activate RtpDemuxer
note left of RtpDemuxer: OutOfOrderCheck()
loop for(auto& payload_type_frequency_map_pair : demultiplex_payload_types){
if(payload.type == map.first && !map.second.payload_name.empty()){
payload.name = std::move(map.second.payload_name);}else{continue;}
}
deactivate RtpDemuxer



group Receive Video

     Note over RTCPSender,RTPSender: SendNackMessagesIfReady(kDefaultRetransmissionTimeMs,kMaxNumberOfStoredPackets,false,true,&nacks_sent_per_ssrc,nacked_sequence_numbers_count);
         Activate RTPSender
             RTPSender ->> TransportInterface: DeliverPacket(RTCPPacketType kRtcp,rtp_header,payload_data,length_of_send_buffer,retransmitted=false,simulcast_id=absl::optional<int>(),pacing_info=PacedInfo());
                 DeActivate RTPSender


          activate PayloadDeliveryController
              PayloadDeliveryController --> NetworkStateEstimatorObserverAdapter: UpdateBandwidthUsage(BandwithUsage usage,Bitrate bitrate,int stream_index=-1,bool use_all_streams=true);
                  PayloadDeliveryController-->TransportCongestionControlClient: SetEstimatedBitRate(int bit_rate_bps,Timestamp at_time,Datarate data_rate=Datarate::Zero(),int num_temporal_layers=kNoTemporalLayering);
                      PayloadDeliveryController-->>PayloadDeliverer: DeliveredBytes(size_t delivered_bytes,size_t header_length=size_t{});
                          PayloadDeliveryController --x PacketRouter: RemoveRembRequest(uint ssrc,uint sender_ssrc);
                              PayloadDeliveryController -[hidden]r-#red PayloadDeliverer

      end






